class Solution:
    def mostBooked(self, n, meetings):
        meetings = sorted(meetings)
        free_time = [0] * n
        count = [0] * n
        for s, e in meetings:
            dur = e - s
            ready = [r for r in range(n) if free_time[r] <= s]
            if ready:
                r = ready[0]
                free_time[r] = s + dur
            else:
                earliest = min(free_time)
                cands = [r for r in range(n) if free_time[r] == earliest]
                r = cands[0]
                free_time[r] = earliest + dur
            count[r] += 1
        best = 0
        for r in range(n):
            if count[r] > count[best]:
                best = r
        return best

