class Solution:
    def mostBooked(self, n, meetings):
        import heapq
        meetings = sorted(meetings)
        free = list(range(n))
        heapq.heapify(free)
        busy = []
        count = [0] * n
        for s, e in meetings:
            dur = e - s
            while busy and busy[0][0] <= s:
                _, room = heapq.heappop(busy)
                heapq.heappush(free, room)
            if free:
                room = heapq.heappop(free)
                heapq.heappush(busy, (s + dur, room))
            else:
                end, room = heapq.heappop(busy)
                heapq.heappush(busy, (end + dur, room))
            count[room] += 1
        best = 0
        for r in range(n):
            if count[r] > count[best]:
                best = r
        return best

