var mostBooked = function(n, meetings) {
    meetings = meetings.slice().sort((a, b) => a[0] - b[0]);
    const count = new Array(n).fill(0);
    const freeTime = new Array(n).fill(0);
    for (const [s, e] of meetings) {
        const dur = e - s;
        let chosen = -1;
        for (let r = 0; r < n; r++) {
            if (freeTime[r] <= s) { chosen = r; break; }
        }
        if (chosen !== -1) {
            freeTime[chosen] = s + dur;
        } else {
            let earliest = Infinity;
            for (let r = 0; r < n; r++) earliest = Math.min(earliest, freeTime[r]);
            for (let r = 0; r < n; r++) {
                if (freeTime[r] === earliest) { chosen = r; break; }
            }
            freeTime[chosen] = earliest + dur;
        }
        count[chosen]++;
    }
    let best = 0;
    for (let r = 0; r < n; r++) if (count[r] > count[best]) best = r;
    return best;
};
